import json
from urllib.parse import quote

import requests

import iv8


API_URL = "https://www.zhipin.com/wapi/zpgeek/search/joblist.json"
UA = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36"

HEADERS = {
    "user-agent": UA,
    "accept": "application/json, text/plain, */*",
    "content-type": "application/x-www-form-urlencoded",
    "origin": "https://www.zhipin.com",
    "referer": "https://www.zhipin.com/web/geek/jobs?query=python&city=101010100",
}
DATA = {
    "scene": "1", "query": "python", "city": "101010100",
    "experience": "", "degree": "", "industry": "", "scale": "",
    "salary": "", "page": "1", "pageSize": "15",
}

session = requests.Session()

# ===== 1. 首次请求，触发 code=37 =====

print("[1] POST joblist API ...")
resp = session.post(API_URL, headers=HEADERS, data=DATA, timeout=15)
payload = resp.json()
print(f"    code={payload.get('code')}  message={payload.get('message')}")

if payload.get("code") != 37:
    print("    未触发 code=37，可能已有有效 cookie，直接输出结果：")
    print(json.dumps(payload, ensure_ascii=False, indent=2)[:500])
    exit()

# ===== 2. 提取 seed/name/ts =====

zp = payload["zpData"]
seed, name, ts = zp["seed"], zp["name"], zp["ts"]
print(f"[2] seed={seed}... name={name} ts={ts}")

# ===== 3. 下载 JS =====

js_url = f"https://www.zhipin.com/web/common/security-js/{name}.js"
print(f"[3] 下载 {js_url}")
js_code = session.get(js_url, headers={"user-agent": UA}, timeout=15).text
print(f"    JS 长度: {len(js_code)}")

# ===== 4. iv8 执行，计算 token =====
print("[4] iv8 计算 __zp_stoken__ ...")

security_url = f"https://www.zhipin.com/web/common/security-check.html?seed={quote(seed)}&name={name}&ts={ts}&callbackUrl=&srcReferer"

environment = {
    "location": {
        "href": security_url,
        "origin": "https://www.zhipin.com",
        "protocol": "https:",
        "host": "www.zhipin.com",
        "hostname": "www.zhipin.com",
        "port": "",
        "pathname": "/web/common/security-check.html",
        "search": "?" + security_url.split("?", 1)[1],
        "hash": ""
    },
    "canvas": {
        "fingerprint": {
            "toDataURL": {
                "png": 'data:image/png;base64,'
            }
        }
    },

    "window": {
        "origin": "https://www.zhipin.com"
    },


}
html_page = f"""<!DOCTYPE html>
<html><head></head><body>
<script src="{js_url}"></script>
</body></html>"""

with iv8.JSContext(environment=environment, config={"timezone": "Asia/Shanghai"}) as ctx:
    ctx.expose({
        "baseURL": environment["location"]["href"],
        "html": html_page,
        "headers": [],
        "resources": {js_url: js_code},
    }, "snapshot")
    ctx.eval("__iv8__.page.load(__iv8__.data.snapshot)")

    seed_escaped = json.dumps(seed, ensure_ascii=False)
    token = ctx.eval(f"encodeURIComponent((new window.ABC).z({seed_escaped}, {int(ts)}));")

print(f"    token={str(token)}...")

# ===== 5. 带 token 重新请求 =====

print("[5] 携带 __zp_stoken__ 重新请求 ...")
session.cookies.set("__zp_stoken__", str(token))
resp2 = session.post(API_URL, headers=HEADERS, data=DATA, timeout=15)
payload2 = resp2.json()
print(f"    code={payload2.get('code')}  message={payload2.get('message')}")

if payload2.get("code") == 0:
    jobs = (payload2.get("zpData") or {}).get("jobList") or []
    print(f"    成功! 获取到 {len(jobs)} 个职位")
    for j in jobs:
        print(f"      - {j.get('jobName')} | {j.get('salaryDesc')} | {j.get('brandName')}")
else:
    print(f"    返回: {json.dumps(payload2, ensure_ascii=False)}")
